const raw = items.length === 1 ? items[0].json : items.map((item) => item.json);
const list = Array.isArray(raw) ? raw : (raw.questions || raw.data || []);
if (!Array.isArray(list) || list.length === 0) throw new Error('questions.json must be an array or { questions: [...] }');
const normalizeOptions = (options) => {
  if (!Array.isArray(options) || options.length < 2) throw new Error('Each question needs at least two options');
  return options.map((option) => typeof option === 'string' ? option : (option.text || option.label || String(option)));
};
const normalizeAnswers = (answers) => {
  const arr = Array.isArray(answers) ? answers : [answers].filter(Boolean);
  if (arr.length === 0) throw new Error('Each question needs a correct answer');
  return arr.map(String);
};
const questions = list.slice(0, 40).map((q, index) => ({
  id: String(q.id || q.questionId || `q-${index + 1}`),
  question: String(q.question || q.text || q.prompt),
  options: normalizeOptions(q.options || q.answers || q.choices),
  correctAnswers: normalizeAnswers(q.correctAnswers || q.correct_answers || q.correctAnswer || q.answer),
  explanation: String(q.explanation || q.rationale || ''),
  ...(q.topic ? { topic: String(q.topic) } : {}),
  ...(q.difficulty ? { difficulty: String(q.difficulty) } : {})
}));
return [{
  json: {
    runId: `n8n-${Date.now()}`,
    title: 'Practice Exam Walkthrough',
    examTitle: 'Practice Exam',
    sourceApp: 'questions-json',
    dryRun: false,
    questions,
    audioAssets: []
  }
}];

const job = items[0].json;
if (job.status === 'failed') throw new Error(job.error || 'Render failed');
const createdAt = Date.parse(job.createdAt || new Date().toISOString());
const elapsedMinutes = (Date.now() - createdAt) / 60000;
if (elapsedMinutes > 90) throw new Error(`Render timed out after ${elapsedMinutes.toFixed(1)} minutes`);
return [{ json: job }];

return [{
  json: {
    status: 'done',
    jobId: $json.id,
    mp4Url: $json.outputUrl,
    metadataUrl: $json.metadataUrl,
    localPath: `/files/data/artifacts/${$json.id}/practice-exam-walkthrough.mp4`,
    message: 'Practice exam walkthrough render complete. Open the MP4 from the mounted data/artifacts folder.'
  }
}];

const uploadEnabled = false;
const payload = items[0].json;
if (!uploadEnabled) {
  return [{
    json: {
      ...payload,
      youtubeUpload: 'skipped',
      reason: 'Human approval received, but YouTube upload is disabled for this POC.',
      nextStep: 'Replace this placeholder with the n8n YouTube upload node and explicitly gate it before enabling production uploads. Historical guard: YOUTUBE_UPLOAD_ENABLED=true.'
    }
  }];
}
return [{
  json: {
    ...payload,
    youtubeUpload: 'ready',
    note: 'Placeholder reached after human approval. Wire the YouTube node here when upload credentials are configured.'
  }
}];
